INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('cpa-moex-01161', 'cpa', 'cpa-moex-104-9023a44f', 'sub-cpa-02', NULL, 'single_choice', 'A 公司以經營連鎖餐廳為主要業務，已掛牌上市，對於該公司股東會議事錄及決議事項之製作及分發， 下列敘述何者正確？', '["股東會之議決事項，應作成議事錄，由主席簽名或蓋章，並於會後三十日內，將議事錄分發各股東", "股東會議事錄之製作及分發，應以書面為之", "股東會議事錄之分發，得以公告方式為之，但應經股東之同意", "董事會應將經股東會決議承認之財務報表及盈餘分派或虧損撥補之決議分發各股東，其分發得以公告 方式為之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:13+00:00", "source_pdf_sha1": "db41a31dadd5", "answer_pdf_sha1": "804900634b63", "source_family": "moex-gov-tw", "moex": {"exam_code": "104130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "104", "exam_name": "104年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01162', 'cpa', 'cpa-moex-104-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '關於股東之出資，下列敘述何者錯誤？', '["無限公司章程若未定公司存續期間，且對於退股無作出特別規定，股東得於年度終了前六個月以書面 通知，聲明於會計年度終了時退股", "無限公司股東死亡或受監護或輔助之宣告時，當然退股", "兩合公司有限責任股東死亡或受監護或輔助之宣告者，發生當然退股之效果", "無限公司章程定有公司存續期限，但股東因有不可歸責於己之重大事由時，得隨時退股"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:13+00:00", "source_pdf_sha1": "db41a31dadd5", "answer_pdf_sha1": "804900634b63", "source_family": "moex-gov-tw", "moex": {"exam_code": "104130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "104", "exam_name": "104年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01163', 'cpa', 'cpa-moex-104-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '公司有下列何種情事，主管機關得依職權或利害關係人之申請，命令解散之？', '["公司辦妥延展登記，而於設立登記後六個月尚未開始營業", "公司未辦理停業登記，而於開始營業後自行停止營業六個月以上", "公司名稱經法院判決確定不得使用，公司於判決確定後三個月內尚未辦妥名稱變更登記", "公司未於設立登記前檢送經會計師查核簽證之文件"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:13+00:00", "source_pdf_sha1": "db41a31dadd5", "answer_pdf_sha1": "804900634b63", "source_family": "moex-gov-tw", "moex": {"exam_code": "104130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "104", "exam_name": "104年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01164', 'cpa', 'cpa-moex-104-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '甲及乙擬合資設立A股份有限公司，對於A公司之設立，下列敘述何者正確？', '["若A公司申請設立登記之資本額低於新臺幣100萬元，得免經會計師查核簽證", "A公司應於申請設立登記時或設立登記後六十日內，檢送經會計師查核簽證之文件", "甲及乙應再尋求一位股東，其股東人數始符合股份有限公司設立之最低標準", "A公司若未於設立登記時或設立登記後三十日內，檢送經會計師查核簽證之文件，主管機關得依職權 或利害關係人之申請，命令解散。但於主管機關命令解散前已檢送者，不在此限"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:13+00:00", "source_pdf_sha1": "db41a31dadd5", "answer_pdf_sha1": "804900634b63", "source_family": "moex-gov-tw", "moex": {"exam_code": "104130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "104", "exam_name": "104年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01165', 'cpa', 'cpa-moex-104-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '關於股份有限公司董事任期未屆滿前改選全體董事之敘述，下列何者正確？', '["該改選全體董事之議案，得以臨時動議提出", "若該次股東會做成原任董事於任期屆滿始為解任之決議，則改選後當選之董事自原任董事任期屆滿時 始就任", "改選全體董事之股東會決議，需有代表已發行股份總數三分之二以上股東之出席", "關於任期未屆滿前改選全體董事之規定，於監察人不適用"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:13+00:00", "source_pdf_sha1": "db41a31dadd5", "answer_pdf_sha1": "804900634b63", "source_family": "moex-gov-tw", "moex": {"exam_code": "104130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "104", "exam_name": "104年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01166', 'cpa', 'cpa-moex-104-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '關於股份有限公司出席股東會使用委託書之說明，下列敘述何者錯誤？', '["公開發行公司之委託書以公司印制之委託書為限，若股東非以公司印制之委託書者，其表決權不予計算", "同一股東得出具二張委託書，分別將不同數量之表決權委託二人代為出席股東會", "股東以書面或電子行使表決權後，並得以委託書委託代理人出席股東會，且以代理人之行使表決權為準", "委託書送達公司後，若股東擬親自出席股東會者，必須於股東會開會二日前以書面通知公司撤銷委託 之意思表示，否則仍以委託代理出席之表決權行使為準"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:13+00:00", "source_pdf_sha1": "db41a31dadd5", "answer_pdf_sha1": "804900634b63", "source_family": "moex-gov-tw", "moex": {"exam_code": "104130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "104", "exam_name": "104年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01167', 'cpa', 'cpa-moex-104-9023a44f', 'sub-cpa-02', NULL, 'single_choice', 'A 股份有限公司以經營連鎖餐飲為主要營業，並未公開發行，則依公司法之規定，下列何項議案得於股 東會以臨時動議提出？', '["解除董事競業禁止義務之議案", "讓與公司全部或主要部分營業或財產之議案", "修正章程之議案", "公司解散之議案"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:13+00:00", "source_pdf_sha1": "db41a31dadd5", "answer_pdf_sha1": "804900634b63", "source_family": "moex-gov-tw", "moex": {"exam_code": "104130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "104", "exam_name": "104年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01168', 'cpa', 'cpa-moex-104-9023a44f', 'sub-cpa-02', NULL, 'single_choice', 'A股份有限公司章程未規定董事及監察人報酬之給予，則下列敘述何者正確？', '["依公司法第202條之規定，董事及監察人報酬為得由董事會決議之項目", "公司章程若未規定董事及監察人報酬者，該公司董事及監察人即屬無給職，不得支領報酬", "在公司未修改章程規定董事及監察人報酬之前，應由董事會決議董事及監察人之報酬", "章程未規定董事報酬者，應由股東會決議其報酬"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:13+00:00", "source_pdf_sha1": "db41a31dadd5", "answer_pdf_sha1": "804900634b63", "source_family": "moex-gov-tw", "moex": {"exam_code": "104130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "104", "exam_name": "104年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01169', 'cpa', 'cpa-moex-104-9023a44f', 'sub-cpa-02', NULL, 'single_choice', 'A股份有限公司已開業15年，最近三年平均稅後淨利，至少應達原定發行公司債應負擔利息（年息）總 額之若干時，始得發行無擔保公司債？', '["50%", "100%", "120%", "150%"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:13+00:00", "source_pdf_sha1": "db41a31dadd5", "answer_pdf_sha1": "804900634b63", "source_family": "moex-gov-tw", "moex": {"exam_code": "104130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "104", "exam_name": "104年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01170', 'cpa', 'cpa-moex-104-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '關於公司債之私募，下列敘述何者正確？', '["私募之發行公司以公開發行股票之公司為限", "私募人數包含金融機構應募者在內，不得超過三十五人", "公司債之私募應於發行後十五日內向證券管理機關報備", "最近三年課稅後平均淨利為負數之公司，不得私募公司債"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:13+00:00", "source_pdf_sha1": "db41a31dadd5", "answer_pdf_sha1": "804900634b63", "source_family": "moex-gov-tw", "moex": {"exam_code": "104130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "104", "exam_name": "104年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL)
